  @Name_e9e7ad81 = N'Magic Link Baseline'
SET
  @Description_e9e7ad81 = N'Restricted role for external users who enter MJ via a magic-link invite. Grants no entity access by default (deny-all baseline). Per-deployment, attach Entity Permissions to this role scoped to ONLY the entities the shared Application exposes — this is the real authorization boundary that keeps external users out of the rest of MJ. Never assign this role to internal/SSO users.' EXEC [${flyway:defaultSchema}].spCreateRole @ID = @ID_e9e7ad81,
